-- Dedicated dining table catalog (separate from table_products)
CREATE TABLE IF NOT EXISTS dining_table_products (
  id bigserial PRIMARY KEY,
  category text,
  name text NOT NULL,
  brand text,
  colour text,
  warranty_in_months int,
  country_of_origin text,
  length text,
  width text,
  height text,
  net_weight text,
  description text,
  generic_name text,
  primary_material_type text,
  primary_material_subtype text,
  primary_room text,
  seating_capacity text,
  product_model_name text,
  price numeric(12,2),
  images_url text,
  product_url text,
  created_at timestamptz DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_dining_table_products_brand ON dining_table_products(brand);
CREATE INDEX IF NOT EXISTS idx_dining_table_products_category ON dining_table_products(category);

ALTER TABLE dining_table_products ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "Allow public read dining_table_products" ON dining_table_products;
CREATE POLICY "Allow public read dining_table_products"
  ON dining_table_products
  FOR SELECT
  USING (true);

