($d$Collection / Dining Chairs$d$, $d$Calix Swivel Metal Dining Chair Set of 2 in Beige Fabric$d$, $d$ByUrban Ladder$d$, $d$options$d$, 12, NULL, $d$62$d$, $d$63$d$, $d$82$d$, $d$21.00 kg$d$, $d$Graceful curves meet modern refinement in the Calix dining chair. Upholstered in a powder-textured fabric, it pairs softness with structure, elevated by elegant contrast piping that outlines its sculpted form. The gently contoured backrest and cushioned seat offer ergonomic comfort, while the sleek metal legs lend a touch of glamour. With a 180° swivel and auto-return feature, Calix adapts effortlessly to your rhythm of dining and conversation. Perfect around a premium dining table or as an accent in a lounge, it’s a chair that feels as good as it looks — poised, contemporary, and luxurious. - Features an 180-degree swivel with an auto return function. - Mid-contoured back. - Available in Beige and Powder Blue colour options.$d$, NULL, $d$Metal$d$, NULL, NULL, NULL, NULL, 21999.0, $d$https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/100x0/YDbrqTufNH-LP.jpg | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/100x0/ikriBhd2S-b.jpg | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/100x0/MxYa8cUW9-a.jpg | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/100x0/xZPt9iuL3c-c.jpg | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/100x0/PW-lIXbGnX-e.jpg | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/100x0/tWtkb_xoxt-h.png | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/original/YDbrqTufNH-LP.jpg | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/150x0/ikriBhd2S-b.jpg | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/150x0/Rnhifb6cZ9-b.jpg | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/200x0/YDbrqTufNH-LP.jpg$d$, $d$https://www.urbanladder.com/product/calix-swivel-metal-dining-chair-set-of-2-in-beige-fabric-9264229$d$),
($d$Collection / Dining Chairs$d$, $d$Oribi Solid Wood Dining Chair Set Of 2 In Teak Finish$d$, $d$ByUrban Ladder$d$, $d$Avocado Green Wheat Brown Out of Stock Burnt Orange$d$, 36, NULL, $d$48$d$, $d$44$d$, $d$88$d$, $d$21.35 kg$d$, $d$The Oribi Dining Chair redefines modern dining with its perfect balance of simplicity, strength, and comfort.  Built with a sturdy medium-back, it offers both support and effortless style, making every meal feel special. Expertly crafted from premium Sheesham wood, it showcases the beauty of solid wood while ensuring lasting durability. The cushioned upholstered seat provides superior comfort, making every meal a relaxed affair. Designed with clean lines and a minimalist aesthetic, the Oribi Dining Chair effortlessly complements any dining setup, from classic to modern. - The upholstered seat is generously cushioned for comfortable dining. - Made of high-grade Sheesham wood. - No assembly required. - Indoor use only.$d$, NULL, $d$Solid Wood$d$, NULL, NULL, NULL, NULL, 9999.0, $d$https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/100x0/js-y0_j00D-01.jpg | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/100x0/Om27UEJGk7-02.png | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/100x0/c6boQ_tEeH-03.png | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/100x0/ujyYZqBq_G-04.jpg | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/100x0/kor5SwnDo6v-05.jpg | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/100x0/ohIwkwpOAEV-06.jpg | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/100x0/MCiPxYD_KVf-07.jpg | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/original/js-y0_j00D-01.jpg | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/150x0/V_BijlC9cS-02.png | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/150x0/Om27UEJGk7-02.png$d$, $d$https://www.urbanladder.com/product/oribi-solid-wood-dining-chair-set-of-in-teak-finish-7519385$d$),
($d$Collection / Dining Chairs$d$, $d$Martha Solid Wood Dining Chair Set Of 2 In Teak Finish$d$, $d$ByUrban Ladder$d$, $d$Burnt Orange Wheat Brown$d$, 36, NULL, $d$51$d$, $d$45$d$, $d$1$d$, $d$19.00 kg$d$, $d$Experience timeless elegance and exceptional comfort with the Martha Dining Chair—a sophisticated addition to any dining space. Crafted from solid Sheesham wood, this chair is a testament to durability and craftsmanship. Designed for both aesthetics and function, the wooden backrest enhances air circulation, promoting comfort even during long meals. Complementing this is a plush, upholstered seat, generously padded and wrapped in premium fabric for a soft yet supportive feel. Whether hosting a formal dinner or enjoying everyday gatherings, the Martha Dining Chair offers the perfect balance of style, comfort, and lasting quality. - Made from solid Sheesham wood. - Upholstered, plush seat. - Please refer to images for dimension details. - Indoor use only.$d$, NULL, $d$Solid Wood$d$, NULL, NULL, NULL, NULL, 9999.0, $d$https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/100x0/677uQTeggT-01.jpg | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/100x0/ojerzvFQsm-02.png | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/100x0/Mk20tddKX7-03.png | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/100x0/OUTNvA0e-R-04.png | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/100x0/XLzFxpS3h0-05.jpg | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/100x0/ivzivYIbL_-06.jpg | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/100x0/fGwMQU7UDt-07.jpg | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/100x0/XEeXSUpVM3-08.jpg | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/original/677uQTeggT-01.jpg | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/150x0/mL95HhKPRUw-02.png$d$, $d$https://www.urbanladder.com/product/martha-solid-wood-dining-chair-set-of-2-in-teak-finish-7519057$d$),
($d$Collection / Dining Chairs$d$, $d$Dane Solid Wood Dining Chair Set of 2 in Honey Finish$d$, $d$ByUrban Ladder$d$, $d$Crush Sale â Up to 70% OFF! Shop Now$d$, 12, NULL, $d$51$d$, $d$49$d$, $d$85$d$, $d$11.50 kg$d$, $d$The Dane dining chair celebrates the elegance of solid wood through a form that feels fluid and enduring. Defined by its softly rounded edges and slender proportions, the design lends a sense of lightness and poise to any dining space. The three gracefully curved slats on the backrest add a sense of rhythm while offering ergonomic support that encourages relaxed seating. Its contoured seat appears to float lightly within the frame, creating visual balance and showcasing the natural beauty of the wood. Perfect for both casual and formal dining settings, the Dane chair blends modern craftsmanship with timeless appeal, making it a versatile choice for interiors that value comfort as much as design clarity. - Made from solid Mango wood. - Available in 2 finish options: Danish Walnut and Honey.$d$, NULL, $d$Solid Wood$d$, NULL, NULL, NULL, NULL, 12999.0, $d$https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/100x0/THVo5ipUM-LP.jpg | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/100x0/dykYiSWZkc-b.jpg | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/100x0/R5X9AyU-j-a.jpg | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/100x0/_V7_PpGiqG-c.jpg | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/100x0/rPLSRTSxqS-d.jpg | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/100x0/9zYfPu-jtv-e.jpg | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/100x0/bZg6S0gG6g-f.png | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/original/THVo5ipUM-LP.jpg | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/150x0/VaM8lz38U-b.jpg | https://cdn.swadeshonline.com/v2/patient-paper-41f385/swad-p/wrkr/products/pictures/item/free/150x0/dykYiSWZkc-b.jpg$d$, $d$https://www.urbanladder.com/product/dane-solid-wood-dining-chair-set-of-2-in-honey-finish-9264243$d$);

CREATE TABLE IF NOT EXISTS dinning_products (
  id bigserial PRIMARY KEY,
  category text,
  name text NOT NULL,
  brand text,
  colour text,
  warranty_in_months int,
  country_of_origin text,
  length text,
  width text,
  height text,
  net_weight text,
  description text,
  generic_name text,
  primary_material_type text,
  primary_material_subtype text,
  primary_room text,
  seating_capacity text,
  product_model_name text,
  price numeric(12,2),
  images_url text,
  product_url text,
  created_at timestamptz DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_dinning_products_brand ON dinning_products(brand);
CREATE INDEX IF NOT EXISTS idx_dinning_products_category ON dinning_products(category);
CREATE INDEX IF NOT EXISTS idx_dinning_products_product_url ON dinning_products(product_url);

ALTER TABLE dinning_products ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "Allow public read dinning_products" ON dinning_products;
CREATE POLICY "Allow public read dinning_products"
  ON dinning_products
  FOR SELECT
  USING (true);

INSERT INTO dinning_products (
  category, name, brand, colour, warranty_in_months, country_of_origin,
  length, width, height, net_weight, description,
  generic_name, primary_material_type, primary_material_subtype, primary_room, seating_capacity, product_model_name,
  price, images_url, product_url
)
SELECT
  category, name, brand, colour, warranty_in_months, country_of_origin,
  length, width, height, net_weight, description,
  generic_name, primary_material_type, primary_material_subtype, primary_room, seating_capacity, product_model_name,
  price, images_url, product_url
FROM dining_table_products;

INSERT INTO dinning_products (
